import{_ as a,a as t}from"./chunks/webdav在win显示效果.BVTuSvY9.js";import{_ as i,o as l,c as d,a2 as r}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"وصول WebDAV للموقع (Beta)","description":"","frontmatter":{},"headers":[],"relativePath":"ar-SA/Safety/webdav-site-access.md","filePath":"ar-SA/Safety/webdav-site-access.md","lastUpdated":1781962217000}'),n={name:"ar-SA/Safety/webdav-site-access.md"};function o(s,e,h,b,p,c){return l(),d("div",null,[...e[0]||(e[0]=[r('<h1 id="وصول-webdav-للموقع-beta" tabindex="-1">وصول WebDAV للموقع (Beta) <a class="header-anchor" href="#وصول-webdav-للموقع-beta" aria-label="Permalink to &quot;وصول WebDAV للموقع (Beta)&quot;">​</a></h1><p>يعرض إعداد WebDAV في Security Settings موقع ImgBed كنقطة WebDAV endpoint.</p><p>بعد تفعيله يمكنك استخدام Windows أو macOS أو مديري الملفات على الجوال أو أي عميل متوافق مع WebDAV لتصفح ملفات ImgBed ورفعها وحذفها وإدارتها مثل مجلد بعيد.</p><p>هذا هو مدخل WebDAV الخاص بالموقع. يختلف عن قناة تخزين WebDAV في إعدادات الرفع. قناة الرفع تحفظ الملفات في خدمة WebDAV خارجية، أما هذا الإعداد فيجعل موقع ImgBed نفسه يوفر وصول WebDAV للعملاء.</p><h2 id="أين-تضبطه؟" tabindex="-1">أين تضبطه؟ <a class="header-anchor" href="#أين-تضبطه؟" aria-label="Permalink to &quot;أين تضبطه؟&quot;">​</a></h2><p>افتح لوحة الإدارة، ثم انتقل إلى:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings -&gt; WebDAV</span></span></code></pre></div><p>الإعدادات المتاحة:</p><ul><li>Enable</li><li>Username</li><li>Password</li><li>Image loading mode</li><li>Default channel</li></ul><h2 id="ماذا-تفعل-هذه-الميزة؟" tabindex="-1">ماذا تفعل هذه الميزة؟ <a class="header-anchor" href="#ماذا-تفعل-هذه-الميزة؟" aria-label="Permalink to &quot;ماذا تفعل هذه الميزة؟&quot;">​</a></h2><p>بعد تفعيل WebDAV يوفر ImgBed رابط وصول ثابتًا:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/dav</span></span></code></pre></div><p>استخدم هذا الرابط للاتصال بمجلد ملفات ImgBed.</p><p>حالات استخدام جيدة:</p><ul><li>تصفح ملفات ImgBed مباشرة من مدير ملفات الكمبيوتر.</li><li>سحب الصور إلى مجلد WebDAV لرفعها.</li><li>تنظيم مجلدات ImgBed من مدير الملفات المحلي.</li><li>استخدام برامج متوافقة مع WebDAV للمزامنة أو إدارة الصور.</li><li>الوصول إلى محتوى ImgBed دون فتح لوحة الإدارة.</li></ul><h2 id="الإعدادات" tabindex="-1">الإعدادات <a class="header-anchor" href="#الإعدادات" aria-label="Permalink to &quot;الإعدادات&quot;">​</a></h2><h3 id="enable" tabindex="-1">Enable <a class="header-anchor" href="#enable" aria-label="Permalink to &quot;Enable&quot;">​</a></h3><p>يفعّل WebDAV endpoint.</p><p>عند تعطيله لا يستطيع العملاء الاتصال عبر WebDAV.</p><h3 id="username-و-password" tabindex="-1">Username و Password <a class="header-anchor" href="#username-و-password" aria-label="Permalink to &quot;Username و Password&quot;">​</a></h3><p>تستخدم هذه البيانات عند اتصال عملاء WebDAV.</p><p>استخدم اسم مستخدم وكلمة مرور مخصصين لـ WebDAV. لا تعِد استخدام كلمة مرور الإدارة أو كلمة مرور الرفع.</p><p>إذا كان اسم المستخدم أو كلمة المرور فارغًا، فلن يتصل عملاء WebDAV بشكل صحيح.</p><h3 id="image-loading-mode" tabindex="-1">Image Loading Mode <a class="header-anchor" href="#image-loading-mode" aria-label="Permalink to &quot;Image Loading Mode&quot;">​</a></h3><p>يحدد Image loading mode رابط الصورة الذي يفضله عملاء WebDAV عند قراءة الصور.</p><p>خيارات شائعة:</p><table tabindex="0"><thead><tr><th>Mode</th><th>الوصف</th></tr></thead><tbody><tr><td>Smart loading</td><td>يختار ImgBed حسب السياق. موصى به للاستخدام العادي.</td></tr><tr><td>Original</td><td>يفضل الصور الأصلية.</td></tr><tr><td>Thumbnail</td><td>يفضل المصغرات. مفيد للمعاينة السريعة.</td></tr></tbody></table><p>إذا لم تكن متأكدًا، اترك <code>Smart loading</code>.</p><h3 id="default-channel" tabindex="-1">Default Channel <a class="header-anchor" href="#default-channel" aria-label="Permalink to &quot;Default Channel&quot;">​</a></h3><p>تُستخدم default channel لرفعات WebDAV.</p><p>عند نسخ ملفات إلى مجلد WebDAV من Windows أو عميل آخر، يرفعها ImgBed عبر قناة الرفع الافتراضية المحددة.</p><p>إذا لم تُحدد قناة افتراضية فقد يعمل التصفح، لكن الرفع قد يفشل.</p><h2 id="الوصول-إلى-webdav-في-windows-11" tabindex="-1">الوصول إلى WebDAV في Windows 11 <a class="header-anchor" href="#الوصول-إلى-webdav-في-windows-11" aria-label="Permalink to &quot;الوصول إلى WebDAV في Windows 11&quot;">​</a></h2><p>يمكن لـ Windows 11 إضافة WebDAV كموقع شبكة.</p><ol><li>افتح <code>This PC</code>.</li><li>اختر <code>Add a network location</code>.</li><li>أدخل <code>https://your-domain.com/dav</code>.</li><li>أدخل WebDAV username و password عند الطلب.</li><li>أكمل المعالج. بعدها يمكن فتح مجلد WebDAV في File Explorer.</li></ol><p><img src="'+a+'" alt="إضافة WebDAV في Windows 11" loading="lazy"></p><p>بعد إضافته يظهر مجلد WebDAV في Windows File Explorer. يمكنك فتح الملفات ونسخها وإدارتها مثل مجلد عادي.</p><p><img src="'+t+'" alt="WebDAV في Windows" loading="lazy"></p><h2 id="العمليات-المدعومة" tabindex="-1">العمليات المدعومة <a class="header-anchor" href="#العمليات-المدعومة" aria-label="Permalink to &quot;العمليات المدعومة&quot;">​</a></h2><p>بعد اتصال WebDAV ناجح يمكنك غالبًا:</p><ul><li>عرض الملفات والمجلدات.</li><li>رفع الملفات.</li><li>إنشاء مجلدات.</li><li>إعادة تسمية الملفات أو المجلدات.</li><li>نقل الملفات.</li><li>حذف الملفات.</li></ul><p>WebDAV مناسب للوصول اليومي وإدارة الملفات الصغيرة. للعمليات الكبيرة أو الحذف الجماعي أو التنظيم المعقد، استخدم لوحة الإدارة.</p><h2 id="login-device-management" tabindex="-1">Login Device Management <a class="header-anchor" href="#login-device-management" aria-label="Permalink to &quot;Login Device Management&quot;">​</a></h2><p>تظهر اتصالات WebDAV الناجحة أيضًا ضمن تبويب WebDAV في Login Device Management.</p><p>يمكنك مراجعة عملاء WebDAV هناك وإجبار الأجهزة القديمة على الخروج عند الحاجة.</p><p>إذا غيّرت WebDAV username أو password فسيحتاج العملاء القدامى إلى تسجيل الدخول مرة أخرى.</p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="windows-يطلب-اسم-المستخدم-وكلمة-المرور-باستمرار" tabindex="-1">Windows يطلب اسم المستخدم وكلمة المرور باستمرار <a class="header-anchor" href="#windows-يطلب-اسم-المستخدم-وكلمة-المرور-باستمرار" aria-label="Permalink to &quot;Windows يطلب اسم المستخدم وكلمة المرور باستمرار&quot;">​</a></h3><p>تحقق من:</p><ul><li>الرابط هو <code>https://your-domain.com/dav</code>.</li><li>اسم المستخدم وكلمة المرور يطابقان إعدادات WebDAV.</li><li>WebDAV مفعّل.</li><li>الموقع يمكن الوصول إليه عبر HTTPS.</li></ul><h3 id="التصفح-يعمل-لكن-الرفع-يفشل" tabindex="-1">التصفح يعمل لكن الرفع يفشل <a class="header-anchor" href="#التصفح-يعمل-لكن-الرفع-يفشل" aria-label="Permalink to &quot;التصفح يعمل لكن الرفع يفشل&quot;">​</a></h3><p>تحقق من <code>Default channel</code>.</p><p>تحتاج رفعات WebDAV إلى قناة رفع افتراضية. إذا كانت مفقودة أو معطلة أو مضبوطة بشكل خاطئ فقد يفشل الرفع.</p><h3 id="سرعة-الوصول-غير-مستقرة" tabindex="-1">سرعة الوصول غير مستقرة <a class="header-anchor" href="#سرعة-الوصول-غير-مستقرة" aria-label="Permalink to &quot;سرعة الوصول غير مستقرة&quot;">​</a></h3><p>يعتمد أداء WebDAV على العميل والشبكة وعدد الملفات وقناة الرفع الافتراضية.</p><p>إذا كان في المجلد ملفات كثيرة، نظمها في مجلدات بدل إبقاء عدد كبير في مجلد واحد.</p><h2 id="توصيات-الأمان" tabindex="-1">توصيات الأمان <a class="header-anchor" href="#توصيات-الأمان" aria-label="Permalink to &quot;توصيات الأمان&quot;">​</a></h2><ul><li>استخدم HTTPS لوصول WebDAV.</li><li>عيّن كلمة مرور قوية.</li><li>لا تشارك كلمة مرور WebDAV مع أشخاص غير موثوقين.</li><li>عطّل WebDAV عندما لا تستخدمه.</li><li>نظّف أجهزة WebDAV غير المستخدمة دوريًا من Login Device Management.</li></ul><h2 id="حجم-ملفات-webdav-المرفوعة" tabindex="-1">حجم ملفات WebDAV المرفوعة <a class="header-anchor" href="#حجم-ملفات-webdav-المرفوعة" aria-label="Permalink to &quot;حجم ملفات WebDAV المرفوعة&quot;">​</a></h2><p>عملاء WebDAV لا يستخدمون مسار تجزئة الملفات الكبيرة الخاص بصفحة الرفع في المتصفح. للملفات التي تتجاوز الحدود المقترحة أدناه، استخدم صفحة الرفع عبر الويب.</p><table tabindex="0"><thead><tr><th>Default Upload Channel</th><th style="text-align:right;">الحد المقترح للملف الواحد عبر WebDAV</th></tr></thead><tbody><tr><td>Telegram</td><td style="text-align:right;">20 MB</td></tr><tr><td>Discord</td><td style="text-align:right;">10 MB</td></tr><tr><td>Cloudflare R2</td><td style="text-align:right;">30 MB</td></tr><tr><td>S3</td><td style="text-align:right;">30 MB</td></tr><tr><td>GitHub Releases</td><td style="text-align:right;">64 MB</td></tr><tr><td>GitLab Packages</td><td style="text-align:right;">64 MB</td></tr><tr><td>Hugging Face</td><td style="text-align:right;">20 MB</td></tr><tr><td>OneDrive</td><td style="text-align:right;">30 MB</td></tr><tr><td>Google Drive</td><td style="text-align:right;">30 MB</td></tr><tr><td>Dropbox</td><td style="text-align:right;">30 MB</td></tr><tr><td>Yandex Disk</td><td style="text-align:right;">30 MB</td></tr><tr><td>pCloud</td><td style="text-align:right;">30 MB</td></tr><tr><td>WebDAV</td><td style="text-align:right;">64 MB</td></tr></tbody></table>',61)])])}const D=i(n,[["render",o]]);export{u as __pageData,D as default};
